import{_ as r,o as t,c as e,ag as p}from"./chunks/framework.ETe_P6d1.js";const s="/kaiping-reports/assets/1.DFTqrEor.jpg",o="/kaiping-reports/assets/2.nKoWMo7A.jpg",i="/kaiping-reports/assets/3.N-u6R6JQ.jpg",n="/kaiping-reports/assets/4.CMFloxE-.jpg",l="/kaiping-reports/assets/5.BEwQbQLs.jpg",h="/kaiping-reports/assets/6.CQ6AQFBS.jpg",c="/kaiping-reports/assets/7.PMkNqFOU.jpg",_="/kaiping-reports/assets/8.D033QDYy.jpg",d="/kaiping-reports/assets/6.D6s979i4.jpg",m="/kaiping-reports/assets/9.pfEnvhY5.jpg",u="/kaiping-reports/assets/11.uInjULXO.jpg",g="/kaiping-reports/assets/12.rSd8huVX.jpg",T=JSON.parse('{"title":"立园碉楼建筑空间类型与形态调查报告","description":"","frontmatter":{},"headers":[],"relativePath":"reports/周颖泽/周颖泽 立园碉楼建筑空间类型与形态调查报告.md","filePath":"reports/周颖泽/周颖泽 立园碉楼建筑空间类型与形态调查报告.md"}'),q={name:"reports/周颖泽/周颖泽 立园碉楼建筑空间类型与形态调查报告.md"};function b(k,a,f,P,x,j){return t(),e("div",null,[...a[0]||(a[0]=[p('<h1 id="立园碉楼建筑空间类型与形态调查报告" tabindex="-1">立园碉楼建筑空间类型与形态调查报告 <a class="header-anchor" href="#立园碉楼建筑空间类型与形态调查报告" aria-label="Permalink to &quot;立园碉楼建筑空间类型与形态调查报告&quot;">​</a></h1><h1 id="考察地点" tabindex="-1">考察地点： <a class="header-anchor" href="#考察地点" aria-label="Permalink to &quot;考察地点：&quot;">​</a></h1><h1 id="考察时间" tabindex="-1">考察时间： <a class="header-anchor" href="#考察时间" aria-label="Permalink to &quot;考察时间：&quot;">​</a></h1><p>考察者：周颖泽</p><h1 id="指导教师" tabindex="-1">指导教师： <a class="header-anchor" href="#指导教师" aria-label="Permalink to &quot;指导教师：&quot;">​</a></h1><h1 id="一、引言" tabindex="-1">一、引言 <a class="header-anchor" href="#一、引言" aria-label="Permalink to &quot;一、引言&quot;">​</a></h1><p>2007年，“开平碉楼与村落”成功列入《世界遗产名录》，成为中国首个华侨文化世界遗产项目，而立园作为其中的核心代表，其碉楼建筑既是近代华侨文化的物质载体，也是中西合璧建筑艺术的典范之作。</p><p>本次研究提出核心问题：立园碉楼作为近代侨乡防御性建筑的典型，其空间类型与形态如何体现防御功能与居住功能的平衡？博物馆化的遗产呈现模式对其空间形态的保护与传承产生了怎样的影响？</p><h1 id="二、案例选取与调研基础" tabindex="-1">二、案例选取与调研基础 <a class="header-anchor" href="#二、案例选取与调研基础" aria-label="Permalink to &quot;二、案例选取与调研基础&quot;">​</a></h1><p>本次调研选取立园（核心案例）、仓东村、赤坎古镇（对比案例），调研围绕空间类型、空间形态、建筑本体、保护模式四大维度，通过实地踏勘、现场拍摄、资料查阅等方式，完成数据收集与分析，确保研究的真实性。</p><p><img src="'+s+'" alt="图1：立园景区平面图"></p><p><img src="'+o+'" alt="图2：立园内部碉楼"></p><h1 id="一-核心案例-立园碉楼建筑概况" tabindex="-1">（一）核心案例：立园碉楼建筑概况 <a class="header-anchor" href="#一-核心案例-立园碉楼建筑概况" aria-label="Permalink to &quot;（一）核心案例：立园碉楼建筑概况&quot;">​</a></h1><p>立园是旅美华侨谢维立先生始建于20世纪初的花园别墅，被誉为“中国华侨园林一绝”，园内别墅区包含六幢别墅与一座古式碉楼——乐天楼，此外泮立楼、泮文楼等别墅也融入了碉楼的防御元素，共同构成立园的碉楼建筑体系。立园碉楼建筑以防御为核心功能，兼顾居住、祭祀等辅助功能，采用钢筋混凝土结构，融合中国传统建筑与西方建筑元素，是近代侨乡碉楼建筑的精品。</p><p><img src="'+i+'" alt="图3： 立园正门"></p><p>​</p><p><img src="'+n+'" alt="图4：  立园后门 "></p><h1 id="二-对比案例选取逻辑" tabindex="-1">（二）对比案例选取逻辑 <a class="header-anchor" href="#二-对比案例选取逻辑" aria-label="Permalink to &quot;（二）对比案例选取逻辑&quot;">​</a></h1><p>选取仓东村、赤坎古镇作为对比案例，核心对比逻辑的是“空间形态与保护模式的差异化”，具体如下：</p><p>仓东村：社区参与的活态保护，空间形态以原生宗族街巷、传统民居为主，，凸显“活态传承”与立园“静态保护”的对比；</p><p>赤坎古镇：整体性改造的文化旅游开发，空间形态以滨江骑楼集群为主，注重整体空间活化，凸显“整体开发”与立园碉楼“单体保护”的对比。</p><p><img src="'+l+'" alt="图5：仓东村"></p><p><img src="'+h+'" alt="图6：赤坎古镇"></p><h1 id="三、案例分析" tabindex="-1">三、案例分析 <a class="header-anchor" href="#三、案例分析" aria-label="Permalink to &quot;三、案例分析&quot;">​</a></h1><p>（一）立园碉楼建筑空间类型与形态专业分析**</p><p>立园碉楼建筑属于“防御—居住复合式空间”，其空间类型与形态严格围绕防御功能展开，同时兼顾居住、祭祀等功能，融合中西建筑风格，形成独特的空间特征，结合建筑史视角，可分为以下两个维度：</p><h1 id="_1-空间类型-防御主导的复合式空间" tabindex="-1">1. 空间类型：防御主导的复合式空间 <a class="header-anchor" href="#_1-空间类型-防御主导的复合式空间" aria-label="Permalink to &quot;1. 空间类型：防御主导的复合式空间&quot;">​</a></h1><p>从空间类型来看，立园碉楼属于近代侨乡防御性民居空间，核心功能是防御匪患、洪涝等现实威胁，同时承担家族居住、祭祀等辅助功能，具体可分为三类子空间：</p><p>1防御空间：主要分布在碉楼顶层与墙体，包括瞭望台、枪眼、厚重墙体、铁制门窗等，其中乐天楼作为谢氏家族的“保安中心”，四周遍布枪眼，门窗皆为铁制，防盗性强，是典型的开平传统式碉楼防御空间</p><p>2居住空间：主要分布在碉楼中层，以泮立楼为例，楼高三层半，一层为厅堂，二层、三层为卧室起居空间，满足家族成员的居住需求</p><p><img src="'+c+'" alt="图7：泮文楼三层平面导览图"></p><p><img src="'+_+'" alt="图8：泮文楼二层平面导览图">3祭祀空间：主要分布在碉楼顶层或顶层半层，如泮立楼最高半层为谢氏家族的神祖龛，屋顶覆盖绿色琉璃瓦，体现中国传统宗族文化和祖宗崇拜，形成“防御—居住—祭祀”三位一体的空间体系。</p><h1 id="_2-空间形态-中西合璧的垂直分层与围合布局" tabindex="-1">2. 空间形态：中西合璧的垂直分层与围合布局 <a class="header-anchor" href="#_2-空间形态-中西合璧的垂直分层与围合布局" aria-label="Permalink to &quot;2. 空间形态：中西合璧的垂直分层与围合布局&quot;">​</a></h1><p>从空间形态来看，立园碉楼呈现“垂直分层、围合封闭”的核心特征，同时融入中西建筑元素，形成独特的空间美学，具体表现为：</p><p>1垂直空间形态：采用垂直分层布局，底层为储物间或厅堂，中层为居住空间，顶层为防御与祭祀空间，形成“下实上虚”的功能结构，既遵循儒家“长幼有序”的伦理秩序，又满足防御与居住的双重需求。</p><p>2平面空间形态：整体呈现方形围合格局，墙体厚重，边界封闭，仅开设少量门窗（以枪眼为主），形成封闭性的空间形态，有效提升防御性能。同时，平面布局融入西方建筑元素，如泮立楼采用欧美式窗户、古罗马式支柱和意大利地砖，与中国传统殿堂式屋顶形成对比，体现中西合璧的建筑风格；</p><p>3细节形态特征：建筑装饰融合中西元素，门楣上的汉字砖雕与拱券上的西洋浮雕并存，灰塑的传统花鸟与彩色玻璃的西洋纹样共生，屋顶采用中国传统琉璃瓦、龙脊，墙体采用西方钢筋混凝土结构。</p><p><img src="'+d+'" alt="图10：泮立楼阳台"> <img src="'+m+'" alt="图9：泮立楼首层室内"></p><p><img src="'+u+'" alt="图11：泮立楼天台"></p><p><img src="'+g+'" alt="图12：泮立楼立剖功能分析"></p><h1 id="二-立园碉楼与对比案例的空间形态对比-凸显核心特征" tabindex="-1">（二）立园碉楼与对比案例的空间形态对比（凸显核心特征） <a class="header-anchor" href="#二-立园碉楼与对比案例的空间形态对比-凸显核心特征" aria-label="Permalink to &quot;（二）立园碉楼与对比案例的空间形态对比（凸显核心特征）&quot;">​</a></h1><p>结合三个对比案例，从空间类型、空间形态、保护模式三个核心维度，与立园碉楼形成对比，清晰凸显立园碉楼的空间特征与保护模式的特殊性，具体如下表所示：</p><p>通过对比可见，立园碉楼的空间形态最具特殊性——以防御为核心，融合中西元素，空间形态固化；而其他三个案例的空间形态均体现“活态”或“更新”特征，与立园碉楼的博物馆化保护形成鲜明对比。</p><h1 id="四、专业视角-建筑史与文化遗产保护理论剖析" tabindex="-1">四、专业视角：建筑史与文化遗产保护理论剖析 <a class="header-anchor" href="#四、专业视角-建筑史与文化遗产保护理论剖析" aria-label="Permalink to &quot;四、专业视角：建筑史与文化遗产保护理论剖析&quot;">​</a></h1><p>从岭南近代侨乡建筑史来看，立园碉楼属于近代侨乡碉楼建筑的成熟期作品，其空间形态的形成与华侨文化、时代背景密切相关：19世纪末至20世纪初，五邑地区大量华侨远渡重洋，积累财富后返乡建宅，为抵御匪患、洪涝，同时彰显家族荣耀，催生了集防御、居住、象征功能于一体的碉楼建筑。立园碉楼作为其中的精品，其空间形态融合了中国传统建筑的围合格局、儒家伦理秩序，与西方建筑的钢筋混凝土结构、装饰元素，是近代华侨文化与中外建筑文化融合的产物，完整呈现了近代侨乡建筑从“防御为主”到“防御与居住结合”的演化脉络。</p><h1 id="五、批判性思考" tabindex="-1">五、批判性思考 <a class="header-anchor" href="#五、批判性思考" aria-label="Permalink to &quot;五、批判性思考&quot;">​</a></h1><h1 id="一-立园碉楼博物馆化保护的优势" tabindex="-1">（一）立园碉楼博物馆化保护的优势 <a class="header-anchor" href="#一-立园碉楼博物馆化保护的优势" aria-label="Permalink to &quot;（一）立园碉楼博物馆化保护的优势&quot;">​</a></h1><p>1.有效保护建筑本体与空间形态：博物馆化的静态封存保护，避免了人为破坏、过度改造等问题，完整保留了立园碉楼的建筑构造。</p><p>2.凸显文化展示价值：通过博物馆化呈现，将碉楼的历史背景、建筑艺术、华侨文化传递给公众，提升了碉楼的文化影响力。</p><h1 id="二-立园碉楼空间保护与形态传承的核心问题" tabindex="-1">（二）立园碉楼空间保护与形态传承的核心问题 <a class="header-anchor" href="#二-立园碉楼空间保护与形态传承的核心问题" aria-label="Permalink to &quot;（二）立园碉楼空间保护与形态传承的核心问题&quot;">​</a></h1><p>1.空间形态固化，丧失原生活力：博物馆化的静态保护，剥离了碉楼的原生居住、祭祀功能，仅保留其物质形态与展示功能，导致空间形态完全固化，无法体现“活态遗产”的价值。与仓东村的活态保护相比，缺乏与当代生活的衔接，空间活力不足；</p><p>2.空间功能单一，文化内涵挖掘不深：碉楼的空间功能仅局限于文化展示，未能充分挖掘其防御空间、居住空间的文化内涵，与赤坎古镇的整体活化相比，未能实现“历史价值与当代功能”的平衡；</p><h1 id="六、结论" tabindex="-1">六、结论 <a class="header-anchor" href="#六、结论" aria-label="Permalink to &quot;六、结论&quot;">​</a></h1><p>本次调研以立园碉楼建筑为核心，围绕空间类型与形态展开专业分析，融入建筑史与文化遗产保护理论，提炼以下核心结论，实现“从现象到本质、从具体到抽象”的研究目标：</p><p>1立园碉楼属于“防御—居住复合式”空间类型，其“垂直分层、围合封闭”的空间形态，融合了中国传统建筑与西方建筑元素；</p><p>2博物馆化保护模式是立园碉楼空间形态得以完整保留的核心保障，其依据文物建筑静态保护、博物馆化呈现理论，有效保护了建筑本体与空间原真性，但同时也导致空间形态固化、功能单一，丧失原生活力，存在明显的保护局限；</p><p>参考文献</p><p>[1]开平碉楼,广东省文物考古研究所，文物出版社</p><p>[2]华侨建筑文化研究,华侨大学建筑学院</p><p>[3]文化遗产保护的理论与实践,同济大学</p><p>[4]广东省文物局. 开平立园建筑保护与研究[M]. 广州：广东人民出版社</p>',61)])])}const D=r(q,[["render",b]]);export{T as __pageData,D as default};
